#include<bits/stdc++.h>
using namespace std;

int c[1000001], cnt = 0;
bool b[1000001];

void f(int n) {
	for (int i = 2; i < n; i++) {
		if (!b[i]) c[cnt++] = i;
		for (int j = 0; c[j] <= n/i ; j++) {
			b[c[j]*i] = 1;
			if (i % c[j] == 0) break;
		}
	}
}

int main() {
	int k, p, m;
	cin >> k;

	f(900001);
	for (int i = 0; i < k; i++) {
		cin >> p;
		m = 0;
		for (int j = 0; c[j]  <= p/2; j++) {
			if (p % c[j] == 0) {
				m++;
			}
		}
		if (m == 2) {
			cout << 1 << endl;
		} else cout << 0 << endl;

	}
	return 0;
}
